function drawCanvas(canvas, w, h, rgb) {
    canvas.width = w;
    canvas.height = h;
    const ctx = canvas.getContext('2d');
    const rgba = new Uint8ClampedArray(w * h * 4);
    for (let i = 0, j = 0; i < rgb.length; i += 3, j += 4) {
        rgba[j] = rgb[i];
        rgba[j + 1] = rgb[i + 1];
        rgba[j + 2] = rgb[i + 2];
        rgba[j + 3] = 255;
    }
    ctx.putImageData(new ImageData(rgba, w, h), 0, 0);
}

